import { useEffect, useMemo, useRef, useState } from "react";
import { Client } from "@heroiclabs/nakama-js";
import type { Match, MatchData, MatchmakerTicket, Session, Socket } from "@heroiclabs/nakama-js";
import "./app.css";

type Mode = "classic" | "timed";
type Mark = "X" | "O";

const OPCODE = {
  STATE: 1,
  MOVE: 2,
  PING: 3,
} as const;

type PublicPlayer = { userId: string; username: string; mark: Mark; connected: boolean };
type PublicState = {
  board: (Mark | "")[];
  players: PublicPlayer[];
  turnUserId: string | null;
  status: "waiting" | "active" | "finished";
  winnerUserId: string | null;
  winningLine: number[] | null;
  moveCount: number;
  label: { open: boolean; mode: Mode };
  turnDeadlineMs: number | null;
};

type Room = { matchId: string; label: { open: boolean; mode: Mode } | null; size: number };

function shortId(id: string) {
  return id.length > 10 ? `${id.slice(0, 6)}…${id.slice(-4)}` : id;
}

function formatMsLeft(deadlineMs: number | null) {
  if (!deadlineMs) return null;
  const left = Math.max(0, deadlineMs - Date.now());
  return Math.ceil(left / 1000);
}

/** Nakama + Lua JSON often encodes cells as an object `{ "0":"X", ... }` instead of an array. */
function normalizeBoard(raw: unknown): (Mark | "")[] {
  if (Array.isArray(raw)) {
    return Array.from({ length: 9 }, (_, i) => {
      const c = raw[i];
      return c === "X" || c === "O" ? c : "";
    });
  }
  if (raw && typeof raw === "object") {
    const o = raw as Record<string, unknown>;
    return Array.from({ length: 9 }, (_, i) => {
      const c = o[String(i)];
      return c === "X" || c === "O" ? c : "";
    });
  }
  return ["", "", "", "", "", "", "", "", ""];
}

function normalizeWinLine(raw: unknown): number[] | null {
  if (!raw || !Array.isArray(raw)) return null;
  return raw.map((n) => Number(n));
}

const API_HOST = "127.0.0.1";
const API_PORT = "7350";
const USE_SSL = false;
const SERVER_KEY = "defaultkey";

function App() {
  const client = useMemo(() => new Client(SERVER_KEY, API_HOST, API_PORT, USE_SSL), []);
  const socketRef = useRef<Socket | null>(null);

  const [session, setSession] = useState<Session | null>(null);
  const [username, setUsername] = useState<string>(() => {
    const saved = localStorage.getItem("ttt.username");
    return saved ?? `player_${Math.floor(Math.random() * 10000)}`;
  });
  const [deviceId] = useState<string>(() => {
    const saved = localStorage.getItem("ttt.deviceId");
    if (saved) return saved;
    const id = crypto.randomUUID();
    localStorage.setItem("ttt.deviceId", id);
    return id;
  });

  const [mode, setMode] = useState<Mode>("classic");
  const [turnTimeSec, setTurnTimeSec] = useState<number>(30);
  const [statusText, setStatusText] = useState<string>("Not connected");
  const [socketReady, setSocketReady] = useState<boolean>(false);

  const [rooms, setRooms] = useState<Array<Room>>([]);
  const [match, setMatch] = useState<Match | null>(null);
  const [state, setState] = useState<PublicState | null>(null);
  const [ticket, setTicket] = useState<MatchmakerTicket | null>(null);

  useEffect(() => {
    localStorage.setItem("ttt.username", username);
  }, [username]);

  async function connect() {
    setStatusText("Authenticating…");
    const s = await client.authenticateDevice(deviceId, true, username);
    console.log(" Session authenticated:", s);
    console.log(" Session user_id:", s.user_id);
    setSession(s);

    setStatusText("Opening realtime socket…");
    setSocketReady(false);
    const sock = client.createSocket(USE_SSL, false);
    socketRef.current = sock;

    sock.ondisconnect = (evt) => {
      console.log(" Socket disconnected:", evt);
      setSocketReady(false);
      setStatusText("Socket disconnected");
    };

    sock.onerror = (error) => {
      console.error(" Socket error:", error);
      setSocketReady(false);
      setStatusText("Socket error");
    };

    sock.onmatchdata = (md: MatchData) => {
      if (md.op_code !== OPCODE.STATE) return;
      try {
        const next = JSON.parse(new TextDecoder().decode(md.data)) as PublicState;
        console.log(" STATE UPDATE from server:", next);
        console.log(" Board:", next.board);
        console.log(" Current turn:", next.turnUserId);
        console.log(" Status:", next.status);
        setState({
          ...next,
          board: normalizeBoard(next.board as unknown),
          winningLine: normalizeWinLine(next.winningLine),
        });
      } catch (err) {
        console.error("❌ Error parsing state update:", err);
      }
    };

    sock.onmatchpresence = () => {
      // state updates are broadcast by server; no-op here
    };

    sock.onmatchmakermatched = async (mm) => {
      setTicket(null);
      setStatusText("Match found. Joining…");
      const m = await sock.joinMatch(mm.match_id);
      setMatch(m);
      setStatusText("In match");
    };

    try {
      console.log(" Connecting socket...");
      await sock.connect(s, true);
      console.log(" Socket connected successfully");
      setSocketReady(true);
      setStatusText("Connected");
      await refreshRooms(s);
    } catch (error) {
      console.error(" Failed to connect socket:", error);
      setStatusText("Connection failed");
      setSocketReady(false);
    }
  }

  async function disconnect() {
    setTicket(null);
    setMatch(null);
    setState(null);
    setRooms([]);
    if (socketRef.current) {
      try {
        await socketRef.current.disconnect(false);
      } catch {
        // ignore
      }
    }
    socketRef.current = null;
    setSocketReady(false);
    setSession(null);
    setStatusText("Disconnected");
  }

  async function refreshRooms(s: Session) {
    // Labels use numeric `open:1` so Bleve can query reliably (+label.open:1).
    // min/max size = rooms still looking for players (0–1 connected).
    let res = await client.listMatches(s, 20, true, "", 0, 1, "+label.open:1");
    let rows = res.matches ?? [];
    if (rows.length === 0) {
      res = await client.listMatches(s, 20, true, "", 0, 2, "*");
      rows = res.matches ?? [];
    }
    const mapped = rows
      .filter((m) => m.match_id && m.size !== undefined)
      .map((m) => ({
        matchId: m.match_id!,
        label: m.label ? safeJson(m.label) : null,
        size: m.size!,
      }))
      .filter((r) => {
        const o = r.label?.open;
        return o === 1 || o === true;
      })
      .filter((r) => r.matchId !== undefined && r.size !== undefined);
    setRooms(mapped as { matchId: string; label: any; size: number }[]);
  }

  function safeJson(s: string) {
    try {
      return JSON.parse(s);
    } catch {
      return s;
    }
  }

  async function createRoom() {
    if (!session) return;
    const sock = socketRef.current;
    if (!sock) return;
    setStatusText("Creating room…");
    try {
      const payload = { mode, turnTimeSec: mode === "timed" ? turnTimeSec : undefined };
      const res = await client.rpc(session, "create-match", payload);
      const { matchId } = res.payload as { matchId: string };
      const m = await sock.joinMatch(matchId);
      setMatch(m);
      setStatusText("Room created — share tab or open another browser to join");
      await refreshRooms(session);
    } catch (e) {
      console.error(e);
      setStatusText(e instanceof Error ? e.message : "Create room failed");
    }
  }

  async function joinRoom(matchId: string) {
    if (!session) return;
    const sock = socketRef.current;
    if (!sock) return;
    setStatusText("Joining room…");
    const m = await sock.joinMatch(matchId);
    setMatch(m);
    setStatusText("In match");
  }

  async function leaveMatch() {
    if (!match) return;
    const sock = socketRef.current;
    if (!sock) return;
    try {
      await sock.leaveMatch(match.match_id);
    } catch {
      // ignore
    }
    setMatch(null);
    setState(null);
    setStatusText("Left match");
    if (session) await refreshRooms(session);
  }

  async function findMatch() {
    if (!session) return;
    const sock = socketRef.current;
    if (!sock) return;
    if (ticket) return;
    setStatusText("Searching…");
    const query = "*";
    const minCount = 2;
    const maxCount = 2;
    const stringProperties = { mode };
    const numericProperties = {};
    const t = await sock.addMatchmaker(query, minCount, maxCount, stringProperties, numericProperties);
    setTicket(t);
    setStatusText("In matchmaking queue");
  }

  async function cancelFindMatch() {
    if (!ticket) return;
    const sock = socketRef.current;
    if (!sock) return;
    try {
      await sock.removeMatchmaker(ticket.ticket);
    } catch {
      // ignore
    }
    setTicket(null);
    setStatusText("Matchmaking cancelled");
  }

  async function play(index: number) {
    console.log("▶️ PLAY() called for cell:", index);
    console.log("Match:", match);
    console.log("Socket:", socketRef.current);
    console.log("isMyTurn:", isMyTurn);
    console.log("Game state:", state);

    if (!match) {
      console.error("❌ PLAY ERROR: No match object");
      return;
    }
    const sock = socketRef.current;
    if (!sock || !socketReady) {
      console.error("❌ PLAY ERROR: Socket connection has not been established yet.");
      return;
    }

    try {
      console.log(" Sending OPCODE.MOVE to server...");
      await sock.sendMatchState(match.match_id, OPCODE.MOVE, JSON.stringify({ index }));
      console.log("✅ PLAY SUCCESS: Move sent to server");
    } catch (e) {
      console.error("❌ PLAY ERROR sending move:", e);
    }
  }

  const me = session?.user_id ?? null;
  const myMark = state?.players.find((p) => p.userId === me)?.mark ?? null;
  const secondsLeft = state?.turnDeadlineMs ? formatMsLeft(state.turnDeadlineMs) : null;
  const isMyTurn = !!(state && me && state.turnUserId === me && state.status === "active");

  // Comprehensive turn calculation logging
  useEffect(() => {
    if (state && match) {
      console.log("===== TURN CALCULATION DEBUG =====");
      console.log("me (user_id):", me);
      console.log("state.turnUserId:", state.turnUserId);
      console.log("state.status:", state.status);
      console.log("meEqualsTurnUserId:", me === state.turnUserId);
      console.log("✅ isMyTurn:", isMyTurn);
      console.log("state.players:", state.players);
      console.log("===================================");
    }
  }, [state, me, isMyTurn, match]);

  useEffect(() => {
    document.addEventListener('click', (e) => {
      // @ts-ignore
      if (e.target && e.target.classList && e.target.classList.contains('cell')) {
        console.log(' Document-level click on .cell', e.target);
      }
    });
  }, []);

  return (
    <div className="page">
      <header className="topbar">
        <div className="brand">
          <div className="title">Tic‑Tac‑Toe</div>
          <div className="subtitle">Nakama authoritative multiplayer</div>
        </div>
        <div className="status">
          <div className="pill">{statusText}</div>
        </div>
      </header>

      {!session ? (
        <section className="card">
          <h2>Connect</h2>
          <div className="row">
            <label>
              Username
              <input value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Your name" />
            </label>
            <button className="primary" onClick={connect} disabled={!username.trim()}>
              Connect
            </button>
          </div>
          <p className="muted">
            Uses device auth. Backend endpoints: API `127.0.0.1:7350`, realtime `127.0.0.1:7352`.
          </p>
        </section>
      ) : (
        <section className="grid">
          <div className="card">
            <div className="cardHeader">
              <h2>Lobby</h2>
              <button onClick={disconnect}>Disconnect</button>
            </div>

            <div className="row">
              <label>
                Mode
                <select value={mode} onChange={(e) => setMode(e.target.value as Mode)} disabled={!!match || !!ticket}>
                  <option value="classic">Classic</option>
                  <option value="timed">Timed</option>
                </select>
              </label>
              <label>
                Turn timer (sec)
                <input
                  type="number"
                  min={5}
                  max={120}
                  value={turnTimeSec}
                  onChange={(e) => setTurnTimeSec(Number(e.target.value))}
                  disabled={mode !== "timed" || !!match || !!ticket}
                />
              </label>
            </div>

            <div className="row">
              <button className="primary" onClick={createRoom} disabled={!!match || !!ticket}>
                Create room
              </button>
              {!ticket ? (
                <button onClick={findMatch} disabled={!!match}>
                  Find match
                </button>
              ) : (
                <button onClick={cancelFindMatch}>Cancel search</button>
              )}
              <button onClick={() => session && refreshRooms(session)} disabled={!!match}>
                Refresh rooms
              </button>
            </div>

            <h3>Open rooms</h3>
            {rooms.length === 0 ? (
              <p className="muted">No open rooms right now.</p>
            ) : (
              <ul className="rooms">
                {rooms.map((r) => (
                  <li key={r.matchId}>
                    <div className="roomMeta">
                      <div className="roomId">{shortId(r.matchId)}</div>
                      <div className="muted">
                        size {r.size} • mode {r.label?.mode ?? "?"}
                      </div>
                    </div>
                    <button onClick={() => joinRoom(r.matchId)} disabled={!!match}>
                      Join
                    </button>
                  </li>
                ))}
              </ul>
            )}

            {/* TEST BUTTON ALWAYS VISIBLE AFTER CONNECTING */}
            <button
              onClick={() => console.log("✅ TEST BUTTON CLICKED - Clicks are working!")}
              style={{ marginTop: "10px", padding: "8px 16px", background: "#4CAF50", color: "white", border: "none", borderRadius: "4px", cursor: "pointer" }}
            >
              Test Click (Always Visible)
            </button>
          </div>

          <div className="card">
            <div className="cardHeader">
              <h2>Match</h2>
              {match ? <button onClick={leaveMatch}>Leave</button> : <span className="muted">Not in a match</span>}
            </div>

            {match && state ? (
              <>
                <div className="matchInfo">
                  <div className="pill">match {shortId(match.match_id)}</div>
                  <div className="pill">
                    you {session.username} {myMark ? `(${myMark})` : ""}
                  </div>
                  <div className="pill">
                    {state.status === "active"
                      ? isMyTurn
                        ? "your turn"
                        : `turn: ${shortId(state.turnUserId ?? "")}`
                      : state.status}
                  </div>
                  {secondsLeft !== null && state.status === "active" ? <div className="pill">{secondsLeft}s</div> : null}
                </div>

                <Board
                  board={state.board}
                  winningLine={state.winningLine}
                  disabled={!isMyTurn}
                  onCellClick={play}
                />

                {/* DEBUG PANEL */}
                <div style={{
                  marginTop: "12px",
                  padding: "10px",
                  background: "#1a1a1a",
                  border: "1px solid #666",
                  borderRadius: "4px",
                  fontSize: "12px",
                  fontFamily: "monospace",
                  color: "#0f0"
                }}>
                  <div>me: {me}</div>
                  <div>turnUserId: {state.turnUserId}</div>
                  <div>status: {state.status}</div>
                  <div>isMyTurn: <span style={{color: isMyTurn ? "#0f0" : "#f00"}}>{String(isMyTurn)}</span></div>
                  <div>disabled: <span style={{color: !isMyTurn ? "#f00" : "#0f0"}}>{String(!isMyTurn)}</span></div>
                  <div>match: {match ? "✓" : "✗"}</div>
                  <div>socket: {socketRef.current ? "✓" : "✗"}</div>
                  <div>socketReady: <span style={{color: socketReady ? "#0f0" : "#f00"}}>{String(socketReady)}</span></div>
                </div>

                <div className="players">
                  {state.players.map((p) => (
                    <div key={p.userId} className="player">
                      <div className="playerName">
                        {p.username} <span className="muted">({p.mark})</span>
                      </div>
                      <div className={p.connected ? "dot ok" : "dot off"} />
                    </div>
                  ))}
                </div>

                {state.status === "finished" ? (
                  <div className="result">
                    {state.winnerUserId
                      ? `Winner: ${state.players.find((p) => p.userId === state.winnerUserId)?.username ?? shortId(state.winnerUserId)}`
                      : "Draw"}
                  </div>
                ) : null}
              </>
            ) : (
              <p className="muted">Create or join a room to start playing.</p>
            )}
          </div>
        </section>
      )}
    </div>
  );
}

function Board({
  board,
  winningLine,
  disabled,
  onCellClick,
}: {
  board: (Mark | "")[];
  winningLine: number[] | null;
  disabled: boolean;
  onCellClick: (index: number) => void;
}) {
  const win = new Set(winningLine ?? []);
  if (disabled) {
    console.warn("⚠️ BOARD DISABLED - isMyTurn is FALSE");
  } else {
    console.log("✅ BOARD ENABLED - isMyTurn is TRUE");
  }

  useEffect(() => {
    const btn = document.querySelector('.cell');
    if (btn) {
      // @ts-ignore
      console.log("DOM button.disabled:", btn.disabled);
    }
  }, [board, disabled]);

  return (
    <div className="board" aria-disabled={disabled}>
      {board.map((cell, idx) => {
        const isWin = win.has(idx);
        const cellDisabled = disabled || cell !== "";
        if (idx === 0) console.log(` BOARD RENDER: disabled=${disabled}, cellDisabled=${cellDisabled}, cell="${cell}"`);
        return (
          <button
            key={idx}
            className={`cell ${isWin ? "win" : ""} ${cellDisabled ? "cell-disabled" : ""}`}
            disabled={cellDisabled}
            onClick={() => {
              if (!cellDisabled) {
                console.log(` Cell ${idx} clicked! cell="${cell}"`);
                onCellClick(idx);
              } else {
                console.log(`❌ Cell ${idx} is disabled, ignoring click`);
              }
            }}
            aria-label={`cell ${idx}`}
            title={`Cell ${idx}${cellDisabled ? " (disabled)" : " (clickable)"}`}
          >
            {cell}
          </button>
        );
      })}
    </div>
  );
}

export default App;

import { useEffect, useMemo, useRef, useState } from "react";
import { Client } from "@heroiclabs/nakama-js";
import type { Match, MatchData, MatchmakerTicket, Session, Socket } from "@heroiclabs/nakama-js";
import "./app.css";

type Mode = "classic" | "timed";
type Mark = "X" | "O";

const OPCODE = {
  STATE: 1,
  MOVE: 2,
  PING: 3,
} as const;

type PublicPlayer = { userId: string; username: string; mark: Mark; connected: boolean };
type PublicState = {
  board: (Mark | "")[];
  players: PublicPlayer[];
  turnUserId: string | null;
  status: "waiting" | "active" | "finished";
  winnerUserId: string | null;
  winningLine: number[] | null;
  moveCount: number;
  label: { open: boolean; mode: Mode };
  turnDeadlineMs: number | null;
};

type Room = { matchId: string; label: { open: boolean; mode: Mode } | null; size: number };

function shortId(id: string) {
  return id.length > 10 ? `${id.slice(0, 6)}…${id.slice(-4)}` : id;
}

function formatMsLeft(deadlineMs: number | null) {
  if (!deadlineMs) return null;
  const left = Math.max(0, deadlineMs - Date.now());
  return Math.ceil(left / 1000);
}

/** Nakama + Lua JSON often encodes cells as an object `{ "0":"X", ... }` instead of an array. */
function normalizeBoard(raw: unknown): (Mark | "")[] {
  if (Array.isArray(raw)) {
    return Array.from({ length: 9 }, (_, i) => {
      const c = raw[i];
      return c === "X" || c === "O" ? c : "";
    });
  }
  if (raw && typeof raw === "object") {
    const o = raw as Record<string, unknown>;
    return Array.from({ length: 9 }, (_, i) => {
      const c = o[String(i)];
      return c === "X" || c === "O" ? c : "";
    });
  }
  return ["", "", "", "", "", "", "", "", ""];
}

function normalizeWinLine(raw: unknown): number[] | null {
  if (!raw || !Array.isArray(raw)) return null;
  return raw.map((n) => Number(n));
}

const API_HOST = "127.0.0.1";
const API_PORT = "7350";
const USE_SSL = false;
const SERVER_KEY = "defaultkey";

function App() {
  const client = useMemo(() => new Client(SERVER_KEY, API_HOST, API_PORT, USE_SSL), []);
  const socketRef = useRef<Socket | null>(null);

  const [session, setSession] = useState<Session | null>(null);
  const [username, setUsername] = useState<string>(() => {
    const saved = localStorage.getItem("ttt.username");
    return saved ?? `player_${Math.floor(Math.random() * 10000)}`;
  });
  const [deviceId] = useState<string>(() => {
    const saved = localStorage.getItem("ttt.deviceId");
    if (saved) return saved;
    const id = crypto.randomUUID();
    localStorage.setItem("ttt.deviceId", id);
    return id;
  });

  const [mode, setMode] = useState<Mode>("classic");
  const [turnTimeSec, setTurnTimeSec] = useState<number>(30);
  const [statusText, setStatusText] = useState<string>("Not connected");
  const [socketReady, setSocketReady] = useState<boolean>(false);

  const [rooms, setRooms] = useState<Array<Room>>([]);
  const [match, setMatch] = useState<Match | null>(null);
  const [state, setState] = useState<PublicState | null>(null);
  const [ticket, setTicket] = useState<MatchmakerTicket | null>(null);

  useEffect(() => {
    localStorage.setItem("ttt.username", username);
  }, [username]);

  async function connect() {
    setStatusText("Authenticating…");
    const s = await client.authenticateDevice(deviceId, true, username);
    console.log(" Session authenticated:", s);
    console.log(" Session user_id:", s.user_id);
    setSession(s);

    setStatusText("Opening realtime socket…");
    setSocketReady(false);
    const sock = client.createSocket(USE_SSL, false);
    socketRef.current = sock;

    sock.ondisconnect = (evt) => {
      console.log(" Socket disconnected:", evt);
      setSocketReady(false);
      setStatusText("Socket disconnected");
    };

    sock.onerror = (error) => {
      console.error(" Socket error:", error);
      setSocketReady(false);
      setStatusText("Socket error");
    };

    sock.onmatchdata = (md: MatchData) => {
      if (md.op_code !== OPCODE.STATE) return;
      try {
        const next = JSON.parse(new TextDecoder().decode(md.data)) as PublicState;
        console.log(" STATE UPDATE from server:", next);
        console.log(" Board:", next.board);
        console.log(" Current turn:", next.turnUserId);
        console.log(" Status:", next.status);
        setState({
          ...next,
          board: normalizeBoard(next.board as unknown),
          winningLine: normalizeWinLine(next.winningLine),
        });
      } catch (err) {
        console.error("❌ Error parsing state update:", err);
      }
    };

    sock.onmatchpresence = () => {
      // state updates are broadcast by server; no-op here
    };

    sock.onmatchmakermatched = async (mm) => {
      setTicket(null);
      setStatusText("Match found. Joining…");
      const m = await sock.joinMatch(mm.match_id);
      setMatch(m);
      setStatusText("In match");
    };

    try {
      console.log(" Connecting socket...");
      await sock.connect(s, true);
      console.log(" Socket connected successfully");
      setSocketReady(true);
      setStatusText("Connected");
      await refreshRooms(s);
    } catch (error) {
      console.error(" Failed to connect socket:", error);
      setStatusText("Connection failed");
      setSocketReady(false);
    }
  }

  async function disconnect() {
    setTicket(null);
    setMatch(null);
    setState(null);
    setRooms([]);
    if (socketRef.current) {
      try {
        await socketRef.current.disconnect(false);
      } catch {
        // ignore
      }
    }
    socketRef.current = null;
    setSocketReady(false);
    setSession(null);
    setStatusText("Disconnected");
  }

  async function refreshRooms(s: Session) {
    // Labels use numeric `open:1` so Bleve can query reliably (+label.open:1).
    // min/max size = rooms still looking for players (0–1 connected).
    let res = await client.listMatches(s, 20, true, "", 0, 1, "+label.open:1");
    let rows = res.matches ?? [];
    if (rows.length === 0) {
      res = await client.listMatches(s, 20, true, "", 0, 2, "*");
      rows = res.matches ?? [];
    }
    const mapped = rows
      .filter((m) => m.match_id && m.size !== undefined)
      .map((m) => ({
        matchId: m.match_id!,
        label: m.label ? safeJson(m.label) : null,
        size: m.size!,
      }))
      .filter((r) => {
        const o = r.label?.open;
        return o === 1 || o === true;
      })
      .filter((r) => r.matchId !== undefined && r.size !== undefined);
    setRooms(mapped as { matchId: string; label: any; size: number }[]);
  }

  function safeJson(s: string) {
    try {
      return JSON.parse(s);
    } catch {
      return s;
    }
  }

  async function createRoom() {
    if (!session) return;
    const sock = socketRef.current;
    if (!sock) return;
    setStatusText("Creating room…");
    try {
      const payload = { mode, turnTimeSec: mode === "timed" ? turnTimeSec : undefined };
      const res = await client.rpc(session, "create-match", payload);
      const { matchId } = res.payload as { matchId: string };
      const m = await sock.joinMatch(matchId);
      setMatch(m);
      setStatusText("Room created — share tab or open another browser to join");
      await refreshRooms(session);
    } catch (e) {
      console.error(e);
      setStatusText(e instanceof Error ? e.message : "Create room failed");
    }
  }

  async function joinRoom(matchId: string) {
    if (!session) return;
    const sock = socketRef.current;
    if (!sock) return;
    setStatusText("Joining room…");
    const m = await sock.joinMatch(matchId);
    setMatch(m);
    setStatusText("In match");
  }

  async function leaveMatch() {
    if (!match) return;
    const sock = socketRef.current;
    if (!sock) return;
    try {
      await sock.leaveMatch(match.match_id);
    } catch {
      // ignore
    }
    setMatch(null);
    setState(null);
    setStatusText("Left match");
    if (session) await refreshRooms(session);
  }

  async function findMatch() {
    if (!session) return;
    const sock = socketRef.current;
    if (!sock) return;
    if (ticket) return;
    setStatusText("Searching…");
    const query = "*";
    const minCount = 2;
    const maxCount = 2;
    const stringProperties = { mode };
    const numericProperties = {};
    const t = await sock.addMatchmaker(query, minCount, maxCount, stringProperties, numericProperties);
    setTicket(t);
    setStatusText("In matchmaking queue");
  }

  async function cancelFindMatch() {
    if (!ticket) return;
    const sock = socketRef.current;
    if (!sock) return;
    try {
      await sock.removeMatchmaker(ticket.ticket);
    } catch {
      // ignore
    }
    setTicket(null);
    setStatusText("Matchmaking cancelled");
  }

  async function play(index: number) {
    console.log("▶️ PLAY() called for cell:", index);
    console.log("Match:", match);
    console.log("Socket:", socketRef.current);
    console.log("isMyTurn:", isMyTurn);
    console.log("Me:", me);
    console.log("Game state:", state);
    console.log("Current turn userId:", state?.turnUserId);

    if (!match) {
      console.error("❌ PLAY ERROR: No match object");
      return;
    }
    if (!state) {
      console.error("❌ PLAY ERROR: No game state");
      return;
    }
    const sock = socketRef.current;
    if (!sock) {
      console.error("❌ PLAY ERROR: No socket");
      return;
    }
    if (!socketReady) {
      console.error("❌ PLAY ERROR: Socket not ready. socketReady =", socketReady);
      return;
    }
    if (!isMyTurn) {
      console.error("❌ PLAY ERROR: Not your turn! me =", me, "turnUserId =", state.turnUserId);
      return;
    }

    try {
      console.log(" Sending OPCODE.MOVE to server for cell", index);
      await sock.sendMatchState(match.match_id, OPCODE.MOVE, JSON.stringify({ index }));
      console.log("✅ PLAY SUCCESS: Move sent to server");
    } catch (e) {
      console.error("❌ PLAY ERROR sending move:", e);
    }
  }

  const me = session?.user_id ?? null;
  const myMark = state?.players.find((p) => p.userId === me)?.mark ?? null;
  const secondsLeft = state?.turnDeadlineMs ? formatMsLeft(state.turnDeadlineMs) : null;
  const isMyTurn = !!(state && me && state.turnUserId === me && state.status === "active");

  // Comprehensive turn calculation logging
  useEffect(() => {
    if (state && match) {
      console.log("===== TURN CALCULATION DEBUG =====");
      console.log("me (user_id):", me);
      console.log("state.turnUserId:", state.turnUserId);
      console.log("state.status:", state.status);
      console.log("meEqualsTurnUserId:", me === state.turnUserId);
      console.log("✅ isMyTurn:", isMyTurn);
      console.log("state.players:", state.players);
      console.log("===================================");
    }
  }, [state, me, isMyTurn, match]);

  useEffect(() => {
    document.addEventListener('click', (e) => {
      // @ts-ignore
      if (e.target && e.target.classList && e.target.classList.contains('cell')) {
        console.log(' Document-level click on .cell', e.target);
      }
    });
  }, []);

  return (
    <div className="page">
      <header className="topbar">
        <div className="brand">
          <div className="title">Tic‑Tac‑Toe</div>
          <div className="subtitle">Nakama authoritative multiplayer</div>
        </div>
        <div className="status">
          <div className="pill">{statusText}</div>
        </div>
      </header>

      {!session ? (
        <section className="card">
          <h2>Connect</h2>
          <div className="row">
            <label>
              Username
              <input value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Your name" />
            </label>
            <button className="primary" onClick={connect} disabled={!username.trim()}>
              Connect
            </button>
          </div>
          <p className="muted">
            Uses device auth. Backend endpoints: API `127.0.0.1:7350`, realtime `127.0.0.1:7352`.
          </p>
        </section>
      ) : (
        <section className="grid">
          <div className="card">
            <div className="cardHeader">
              <h2>Lobby</h2>
              <button onClick={disconnect}>Disconnect</button>
            </div>

            <div className="row">
              <label>
                Mode
                <select value={mode} onChange={(e) => setMode(e.target.value as Mode)} disabled={!!match || !!ticket}>
                  <option value="classic">Classic</option>
                  <option value="timed">Timed</option>
                </select>
              </label>
              <label>
                Turn timer (sec)
                <input
                  type="number"
                  min={5}
                  max={120}
                  value={turnTimeSec}
                  onChange={(e) => setTurnTimeSec(Number(e.target.value))}
                  disabled={mode !== "timed" || !!match || !!ticket}
                />
              </label>
            </div>

            <div className="row">
              <button className="primary" onClick={createRoom} disabled={!!match || !!ticket}>
                Create room
              </button>
              {!ticket ? (
                <button onClick={findMatch} disabled={!!match}>
                  Find match
                </button>
              ) : (
                <button onClick={cancelFindMatch}>Cancel search</button>
              )}
              <button onClick={() => session && refreshRooms(session)} disabled={!!match}>
                Refresh rooms
              </button>
            </div>

            <h3>Open rooms</h3>
            {rooms.length === 0 ? (
              <p className="muted">No open rooms right now.</p>
            ) : (
              <ul className="rooms">
                {rooms.map((r) => (
                  <li key={r.matchId}>
                    <div className="roomMeta">
                      <div className="roomId">{shortId(r.matchId)}</div>
                      <div className="muted">
                        size {r.size} • mode {r.label?.mode ?? "?"}
                      </div>
                    </div>
                    <button onClick={() => joinRoom(r.matchId)} disabled={!!match}>
                      Join
                    </button>
                  </li>
                ))}
              </ul>
            )}

            {/* TEST BUTTON ALWAYS VISIBLE AFTER CONNECTING */}
            <button
              onClick={() => console.log("✅ TEST BUTTON CLICKED - Clicks are working!")}
              style={{ marginTop: "10px", padding: "8px 16px", background: "#4CAF50", color: "white", border: "none", borderRadius: "4px", cursor: "pointer" }}
            >
              Test Click (Always Visible)
            </button>
          </div>

          <div className="card">
            <div className="cardHeader">
              <h2>Match</h2>
              {match ? <button onClick={leaveMatch}>Leave</button> : <span className="muted">Not in a match</span>}
            </div>

            {match && state ? (
              <>
                <div className="matchInfo">
                  <div className="pill">match {shortId(match.match_id)}</div>
                  <div className="pill">
                    you {session.username} {myMark ? `(${myMark})` : ""}
                  </div>
                  <div className="pill">
                    {state.status === "active"
                      ? isMyTurn
                        ? "your turn"
                        : `turn: ${shortId(state.turnUserId ?? "")}`
                      : state.status}
                  </div>
                  {secondsLeft !== null && state.status === "active" ? <div className="pill">{secondsLeft}s</div> : null}
                </div>

                <Board
                  board={state.board}
                  winningLine={state.winningLine}
                  disabled={!isMyTurn}
                  onCellClick={play}
                />

                {/* DEBUG PANEL */}
                <div style={{
                  marginTop: "12px",
                  padding: "10px",
                  background: "#1a1a1a",
                  border: "1px solid #666",
                  borderRadius: "4px",
                  fontSize: "12px",
                  fontFamily: "monospace",
                  color: "#0f0"
                }}>
                  <div>me: {me}</div>
                  <div>turnUserId: {state.turnUserId}</div>
                  <div>status: {state.status}</div>
                  <div>isMyTurn: <span style={{color: isMyTurn ? "#0f0" : "#f00"}}>{String(isMyTurn)}</span></div>
                  <div>disabled: <span style={{color: !isMyTurn ? "#f00" : "#0f0"}}>{String(!isMyTurn)}</span></div>
                  <div>match: {match ? "✓" : "✗"}</div>
                  <div>socket: {socketRef.current ? "✓" : "✗"}</div>
                  <div>socketReady: <span style={{color: socketReady ? "#0f0" : "#f00"}}>{String(socketReady)}</span></div>
                </div>

                <div className="players">
                  {state.players.map((p) => (
                    <div key={p.userId} className="player">
                      <div className="playerName">
                        {p.username} <span className="muted">({p.mark})</span>
                      </div>
                      <div className={p.connected ? "dot ok" : "dot off"} />
                    </div>
                  ))}
                </div>

                {state.status === "finished" ? (
                  <div className="result">
                    {state.winnerUserId
                      ? `Winner: ${state.players.find((p) => p.userId === state.winnerUserId)?.username ?? shortId(state.winnerUserId)}`
                      : "Draw"}
                  </div>
                ) : null}
              </>
            ) : (
              <p className="muted">Create or join a room to start playing.</p>
            )}
          </div>
        </section>
      )}
    </div>
  );
}

function Board({
  board,
  winningLine,
  disabled,
  onCellClick,
}: {
  board: (Mark | "")[];
  winningLine: number[] | null;
  disabled: boolean;
  onCellClick: (index: number) => void;
}) {
  const win = new Set(winningLine ?? []);
  if (disabled) {
    console.warn("⚠️ BOARD DISABLED - isMyTurn is FALSE");
  } else {
    console.log("✅ BOARD ENABLED - isMyTurn is TRUE");
  }

  useEffect(() => {
    const btn = document.querySelector('.cell');
    if (btn) {
      // @ts-ignore
      console.log("DOM button.disabled:", btn.disabled);
    }
  }, [board, disabled]);

  return (
    <div className="board" aria-disabled={disabled}>
      {board.map((cell, idx) => {
        const isWin = win.has(idx);
        const cellDisabled = disabled || cell !== "";
        if (idx === 0) console.log(` BOARD RENDER: disabled=${disabled}, cellDisabled=${cellDisabled}, cell="${cell}"`);
        return (
          <button
            key={idx}
            className={`cell ${isWin ? "win" : ""} ${cellDisabled ? "cell-disabled" : ""}`}
            disabled={cellDisabled}
            onClick={() => {
              if (!cellDisabled) {
                console.log(` Cell ${idx} clicked! cell="${cell}"`);
                onCellClick(idx);
              } else {
                console.log(`❌ Cell ${idx} is disabled, ignoring click`);
              }
            }}
            aria-label={`cell ${idx}`}
            title={`Cell ${idx}${cellDisabled ? " (disabled)" : " (clickable)"}`}
          >
            {cell}
          </button>
        );
      })}
    </div>
  );
}

export default App;

/* eslint-disable @typescript-eslint/no-explicit-any */

const OPCODE = {
  STATE: 1,
  MOVE: 2,
  PING: 3,
} as const;

type Mode = "classic" | "timed";
type Mark = "X" | "O";
type GameStatus = "waiting" | "active" | "finished";

type MatchLabel = {
  open: boolean;
  mode: Mode;
};

type PlayerInfo = {
  userId: string;
  username: string;
  mark: Mark;
  presence: nkruntime.Presence;
  connected: boolean;
};

type MatchState = {
  board: (Mark | "")[];
  players: Record<string, PlayerInfo>;
  marksByUserId: Record<string, Mark>;
  turnUserId: string | null;
  status: GameStatus;
  winnerUserId: string | null;
  winningLine: number[] | null;
  moveCount: number;
  lastMoveAtMs: number;
  createdAtMs: number;
  label: MatchLabel;
  tickRate: number;
  turnTimeSec: number | null;
  turnDeadlineMs: number | null;
};

const WIN_LINES: number[][] = [
  [0, 1, 2],
  [3, 4, 5],
  [6, 7, 8],
  [0, 3, 6],
  [1, 4, 7],
  [2, 5, 8],
  [0, 4, 8],
  [2, 4, 6],
];

function nowMs(): number {
  return Date.now();
}

function computeWinner(board: (Mark | "")[]): { mark: Mark; line: number[] } | null {
  for (const line of WIN_LINES) {
    const [a, b, c] = line;
    const v = board[a];
    if (v && v === board[b] && v === board[c]) return { mark: v, line };
  }
  return null;
}

function isBoardFull(board: (Mark | "")[]): boolean {
  return board.every((c) => c !== "");
}

function otherMark(mark: Mark): Mark {
  return mark === "X" ? "O" : "X";
}

function buildPublicState(state: MatchState) {
  const players = Object.values(state.players).map((p) => ({
    userId: p.userId,
    username: p.username,
    mark: p.mark,
    connected: p.connected,
  }));

  return {
    board: state.board,
    players,
    turnUserId: state.turnUserId,
    status: state.status,
    winnerUserId: state.winnerUserId,
    winningLine: state.winningLine,
    moveCount: state.moveCount,
    label: state.label,
    turnDeadlineMs: state.turnDeadlineMs,
  };
}

function broadcastState(dispatcher: nkruntime.MatchDispatcher, state: MatchState) {
  dispatcher.broadcastMessage(OPCODE.STATE, JSON.stringify(buildPublicState(state)), null, null, true);
}

function assignMarks(state: MatchState, joiningUserId: string): void {
  const usedMarks = new Set(Object.values(state.marksByUserId));
  const mark: Mark = usedMarks.has("X") ? "O" : "X";
  state.marksByUserId[joiningUserId] = mark;
}

function chooseFirstTurn(state: MatchState): void {
  const userIds = Object.keys(state.players).sort();
  const xUser = userIds.find((u) => state.marksByUserId[u] === "X");
  state.turnUserId = xUser ?? (userIds[0] ?? null);
  if (state.label.mode === "timed") {
    state.turnDeadlineMs = nowMs() + (state.turnTimeSec ?? 30) * 1000;
  } else {
    state.turnDeadlineMs = null;
  }
}

function setNextTurn(state: MatchState): void {
  if (!state.turnUserId) return;
  const current = state.turnUserId;
  const currentMark = state.marksByUserId[current];
  if (!currentMark) return;
  const nextMark = otherMark(currentMark);
  const nextUser = Object.keys(state.marksByUserId).find((uid) => state.marksByUserId[uid] === nextMark) ?? null;
  state.turnUserId = nextUser;
  if (state.label.mode === "timed") {
    state.turnDeadlineMs = nowMs() + (state.turnTimeSec ?? 30) * 1000;
  } else {
    state.turnDeadlineMs = null;
  }
}

let matchInit: nkruntime.MatchInitFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  params: Record<string, any> | null
) {
    const mode: Mode = params?.mode === "timed" ? "timed" : "classic";
    const turnTimeSecRaw = typeof params?.turnTimeSec === "number" ? params.turnTimeSec : 30;
    const turnTimeSec = mode === "timed" ? Math.max(5, Math.min(120, Math.floor(turnTimeSecRaw))) : null;
    const tickRate = 5;

    const state: MatchState = {
      board: Array(9).fill(""),
      players: {},
      marksByUserId: {},
      turnUserId: null,
      status: "waiting",
      winnerUserId: null,
      winningLine: null,
      moveCount: 0,
      lastMoveAtMs: 0,
      createdAtMs: nowMs(),
      label: { open: true, mode },
      tickRate,
      turnTimeSec,
      turnDeadlineMs: null,
    };

    const label = JSON.stringify(state.label);
    return { state, tickRate, label };
  };

let matchJoinAttempt: nkruntime.MatchJoinAttemptFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  presence: nkruntime.Presence,
  metadata: Record<string, any> | null
) {
    if (Object.keys(state.players).length >= 2 && !state.players[presence.userId]) {
      return { state, accept: false, reason: "match full" };
    }
    if (state.status === "finished" && !state.players[presence.userId]) {
      return { state, accept: false, reason: "match finished" };
    }
    return { state, accept: true };
  };

let matchJoin: nkruntime.MatchJoinFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  presences: nkruntime.Presence[]
) {
    for (const p of presences) {
      if (!state.players[p.userId]) assignMarks(state, p.userId);
      const mark = state.marksByUserId[p.userId] ?? "X";
      state.players[p.userId] = { userId: p.userId, username: p.username, mark, presence: p, connected: true };
    }

    const count = Object.keys(state.players).length;
    if (count >= 2 && state.status === "waiting") {
      state.status = "active";
      state.label.open = false;
      chooseFirstTurn(state);
    } else {
      state.label.open = count < 2;
    }

    broadcastState(dispatcher, state);
    return { state };
  };

let matchLeave: nkruntime.MatchLeaveFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  presences: nkruntime.Presence[]
) {
    for (const p of presences) {
      const existing = state.players[p.userId];
      if (existing) {
        existing.connected = false;
        existing.presence = p;
      }
    }

    if (state.status === "active") {
      const connectedUsers = Object.values(state.players).filter((pl) => pl.connected).map((pl) => pl.userId);
      if (connectedUsers.length === 1) {
        state.status = "finished";
        state.winnerUserId = connectedUsers[0];
        state.winningLine = null;
        state.turnUserId = null;
        state.label.open = false;
        state.turnDeadlineMs = null;
      }
    }

    broadcastState(dispatcher, state);
    return { state };
  };

let matchLoop: nkruntime.MatchLoopFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  messages: nkruntime.MatchMessage[]
) {
    if (state.status === "active" && state.label.mode === "timed" && state.turnUserId && state.turnDeadlineMs) {
      if (nowMs() > state.turnDeadlineMs) {
        const loser = state.turnUserId;
        const loserMark = state.marksByUserId[loser];
        const winner =
          (loserMark &&
            Object.keys(state.marksByUserId).find((uid) => state.marksByUserId[uid] === otherMark(loserMark))) ??
          null;
        state.status = "finished";
        state.winnerUserId = winner;
        state.winningLine = null;
        state.turnUserId = null;
        state.label.open = false;
        state.turnDeadlineMs = null;
        broadcastState(dispatcher, state);
      }
    }

    for (const m of messages) {
      if (m.opCode === OPCODE.PING) continue;
      if (m.opCode !== OPCODE.MOVE) continue;
      if (state.status !== "active") continue;
      if (!state.turnUserId) continue;
      if (m.sender.userId !== state.turnUserId) continue;

      let payload: any;
      try {
        payload = JSON.parse(nk.binaryToString(m.data));
      } catch {
        continue;
      }

      const index = Number(payload?.index);
      if (!Number.isInteger(index) || index < 0 || index > 8) continue;
      if (state.board[index] !== "") continue;

      const mark = state.marksByUserId[m.sender.userId];
      if (!mark) continue;

      state.board[index] = mark;
      state.moveCount += 1;
      state.lastMoveAtMs = nowMs();

      const winner = computeWinner(state.board);
      if (winner) {
        state.status = "finished";
        state.winnerUserId =
          Object.keys(state.marksByUserId).find((uid) => state.marksByUserId[uid] === winner.mark) ?? null;
        state.winningLine = winner.line;
        state.turnUserId = null;
        state.turnDeadlineMs = null;
        state.label.open = false;
      } else if (isBoardFull(state.board)) {
        state.status = "finished";
        state.winnerUserId = null;
        state.winningLine = null;
        state.turnUserId = null;
        state.turnDeadlineMs = null;
        state.label.open = false;
      } else {
        setNextTurn(state);
      }

      broadcastState(dispatcher, state);
    }

    return { state };
  };

let matchTerminate: nkruntime.MatchTerminateFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  graceSeconds: number
) {
    return { state };
  };

let matchSignal: nkruntime.MatchSignalFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  data: string
) {
    // Not used in this implementation, but required by some Nakama versions to avoid crashes
    // during match registration/introspection.
    return { state, data: "" };
  };

const RPC_CREATE_MATCH = "create-match";

type CreateMatchPayload = {
  mode?: Mode;
  turnTimeSec?: number;
};

function parseJson<T>(s: string | undefined): T | null {
  if (!s) return null;
  try {
    return JSON.parse(s) as T;
  } catch {
    return null;
  }
}

function CreateMatchRpc(ctx: nkruntime.Context, logger: nkruntime.Logger, nk: nkruntime.Nakama, payload: string) {
  const req = parseJson<CreateMatchPayload>(payload) ?? {};
  const mode: Mode = req.mode === "timed" ? "timed" : "classic";
  const turnTimeSec = typeof req.turnTimeSec === "number" ? req.turnTimeSec : undefined;
  const matchId = nk.matchCreate("tictactoe", { mode, turnTimeSec });
  return JSON.stringify({ matchId });
}

function OnMatchmakerMatched(ctx: nkruntime.Context, logger: nkruntime.Logger, nk: nkruntime.Nakama) {
  const matchId = nk.matchCreate("tictactoe", { mode: "classic" });
  return matchId;
}

function beforeMatchmakerAdd(
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  envelope: nkruntime.Envelope
) {
  if (envelope.matchmakerAdd) {
    envelope.matchmakerAdd.minCount = 2;
    envelope.matchmakerAdd.maxCount = 2;
    const mode = envelope.matchmakerAdd.stringProperties?.["mode"];
    if (mode !== "timed" && mode !== "classic") {
      if (!envelope.matchmakerAdd.stringProperties) envelope.matchmakerAdd.stringProperties = {};
      envelope.matchmakerAdd.stringProperties["mode"] = "classic";
    }
  }
  return envelope;
}

function InitModule(ctx: nkruntime.Context, logger: nkruntime.Logger, nk: nkruntime.Nakama, initializer: nkruntime.Initializer) {
  initializer.registerMatch("tictactoe", {
    matchInit,
    matchJoinAttempt,
    matchJoin,
    matchLeave,
    matchLoop,
    matchSignal,
    matchTerminate,
  });
  initializer.registerRpc(RPC_CREATE_MATCH, CreateMatchRpc);
  initializer.registerMatchmakerMatched(OnMatchmakerMatched);
  initializer.registerRtBefore("MatchmakerAdd", beforeMatchmakerAdd);
  logger.info("Lila TicTacToe module loaded.");
}

// Reference InitModule so build tools don't remove it
!InitModule && InitModule.bind(null);

/* eslint-disable @typescript-eslint/no-explicit-any */

const OPCODE = {
  STATE: 1,
  MOVE: 2,
  PING: 3,
} as const;

type Mode = "classic" | "timed";
type Mark = "X" | "O";
type GameStatus = "waiting" | "active" | "finished";

type MatchLabel = {
  open: boolean;
  mode: Mode;
};

type PlayerInfo = {
  userId: string;
  username: string;
  mark: Mark;
  presence: nkruntime.Presence;
  connected: boolean;
};

type MatchState = {
  board: (Mark | "")[];
  players: Record<string, PlayerInfo>;
  marksByUserId: Record<string, Mark>;
  turnUserId: string | null;
  status: GameStatus;
  winnerUserId: string | null;
  winningLine: number[] | null;
  moveCount: number;
  lastMoveAtMs: number;
  createdAtMs: number;
  label: MatchLabel;
  tickRate: number;
  turnTimeSec: number | null;
  turnDeadlineMs: number | null;
};

const WIN_LINES: number[][] = [
  [0, 1, 2],
  [3, 4, 5],
  [6, 7, 8],
  [0, 3, 6],
  [1, 4, 7],
  [2, 5, 8],
  [0, 4, 8],
  [2, 4, 6],
];

function nowMs(): number {
  return Date.now();
}

function computeWinner(board: (Mark | "")[]): { mark: Mark; line: number[] } | null {
  for (const line of WIN_LINES) {
    const [a, b, c] = line;
    const v = board[a];
    if (v && v === board[b] && v === board[c]) return { mark: v, line };
  }
  return null;
}

function isBoardFull(board: (Mark | "")[]): boolean {
  return board.every((c) => c !== "");
}

function otherMark(mark: Mark): Mark {
  return mark === "X" ? "O" : "X";
}

function buildPublicState(state: MatchState) {
  const players = Object.values(state.players).map((p) => ({
    userId: p.userId,
    username: p.username,
    mark: p.mark,
    connected: p.connected,
  }));

  return {
    board: state.board,
    players,
    turnUserId: state.turnUserId,
    status: state.status,
    winnerUserId: state.winnerUserId,
    winningLine: state.winningLine,
    moveCount: state.moveCount,
    label: state.label,
    turnDeadlineMs: state.turnDeadlineMs,
  };
}

function broadcastState(dispatcher: nkruntime.MatchDispatcher, state: MatchState) {
  dispatcher.broadcastMessage(OPCODE.STATE, JSON.stringify(buildPublicState(state)), null, null, true);
}

function assignMarks(state: MatchState, joiningUserId: string): void {
  const usedMarks = new Set(Object.values(state.marksByUserId));
  const mark: Mark = usedMarks.has("X") ? "O" : "X";
  state.marksByUserId[joiningUserId] = mark;
}

function chooseFirstTurn(state: MatchState): void {
  const userIds = Object.keys(state.players).sort();
  const xUser = userIds.find((u) => state.marksByUserId[u] === "X");
  state.turnUserId = xUser ?? (userIds[0] ?? null);
  if (state.label.mode === "timed") {
    state.turnDeadlineMs = nowMs() + (state.turnTimeSec ?? 30) * 1000;
  } else {
    state.turnDeadlineMs = null;
  }
}

function setNextTurn(state: MatchState): void {
  if (!state.turnUserId) return;
  const current = state.turnUserId;
  const currentMark = state.marksByUserId[current];
  if (!currentMark) return;
  const nextMark = otherMark(currentMark);
  const nextUser = Object.keys(state.marksByUserId).find((uid) => state.marksByUserId[uid] === nextMark) ?? null;
  state.turnUserId = nextUser;
  if (state.label.mode === "timed") {
    state.turnDeadlineMs = nowMs() + (state.turnTimeSec ?? 30) * 1000;
  } else {
    state.turnDeadlineMs = null;
  }
}

let matchInit: nkruntime.MatchInitFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  params: Record<string, any> | null
) {
    const mode: Mode = params?.mode === "timed" ? "timed" : "classic";
    const turnTimeSecRaw = typeof params?.turnTimeSec === "number" ? params.turnTimeSec : 30;
    const turnTimeSec = mode === "timed" ? Math.max(5, Math.min(120, Math.floor(turnTimeSecRaw))) : null;
    const tickRate = 5;

    const state: MatchState = {
      board: Array(9).fill(""),
      players: {},
      marksByUserId: {},
      turnUserId: null,
      status: "waiting",
      winnerUserId: null,
      winningLine: null,
      moveCount: 0,
      lastMoveAtMs: 0,
      createdAtMs: nowMs(),
      label: { open: true, mode },
      tickRate,
      turnTimeSec,
      turnDeadlineMs: null,
    };

    const label = JSON.stringify(state.label);
    return { state, tickRate, label };
  };

let matchJoinAttempt: nkruntime.MatchJoinAttemptFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  presence: nkruntime.Presence,
  metadata: Record<string, any> | null
) {
    if (Object.keys(state.players).length >= 2 && !state.players[presence.userId]) {
      return { state, accept: false, reason: "match full" };
    }
    if (state.status === "finished" && !state.players[presence.userId]) {
      return { state, accept: false, reason: "match finished" };
    }
    return { state, accept: true };
  };

let matchJoin: nkruntime.MatchJoinFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  presences: nkruntime.Presence[]
) {
    for (const p of presences) {
      if (!state.players[p.userId]) assignMarks(state, p.userId);
      const mark = state.marksByUserId[p.userId] ?? "X";
      state.players[p.userId] = { userId: p.userId, username: p.username, mark, presence: p, connected: true };
    }

    const count = Object.keys(state.players).length;
    if (count >= 2 && state.status === "waiting") {
      state.status = "active";
      state.label.open = false;
      chooseFirstTurn(state);
    } else {
      state.label.open = count < 2;
    }

    broadcastState(dispatcher, state);
    return { state };
  };

let matchLeave: nkruntime.MatchLeaveFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  presences: nkruntime.Presence[]
) {
    for (const p of presences) {
      const existing = state.players[p.userId];
      if (existing) {
        existing.connected = false;
        existing.presence = p;
      }
    }

    if (state.status === "active") {
      const connectedUsers = Object.values(state.players).filter((pl) => pl.connected).map((pl) => pl.userId);
      if (connectedUsers.length === 1) {
        state.status = "finished";
        state.winnerUserId = connectedUsers[0];
        state.winningLine = null;
        state.turnUserId = null;
        state.label.open = false;
        state.turnDeadlineMs = null;
      }
    }

    broadcastState(dispatcher, state);
    return { state };
  };

let matchLoop: nkruntime.MatchLoopFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  messages: nkruntime.MatchMessage[]
) {
    if (state.status === "active" && state.label.mode === "timed" && state.turnUserId && state.turnDeadlineMs) {
      if (nowMs() > state.turnDeadlineMs) {
        const loser = state.turnUserId;
        const loserMark = state.marksByUserId[loser];
        const winner =
          (loserMark &&
            Object.keys(state.marksByUserId).find((uid) => state.marksByUserId[uid] === otherMark(loserMark))) ??
          null;
        state.status = "finished";
        state.winnerUserId = winner;
        state.winningLine = null;
        state.turnUserId = null;
        state.label.open = false;
        state.turnDeadlineMs = null;
        broadcastState(dispatcher, state);
      }
    }

    for (const m of messages) {
      if (m.opCode === OPCODE.PING) continue;
      if (m.opCode !== OPCODE.MOVE) {
        logger.info(`[MATCHLOOP] Skipping non-MOVE opCode: ${m.opCode}`);
        continue;
      }

      logger.info(`[MATCHLOOP] Received MOVE from ${m.sender.userId}`);
      logger.info(`[MATCHLOOP] Game status: ${state.status}, turnUserId: ${state.turnUserId}`);

      if (state.status !== "active") {
        logger.warn(`[MATCHLOOP] Game not active, status: ${state.status}`);
        continue;
      }
      if (!state.turnUserId) {
        logger.warn(`[MATCHLOOP] No turn user ID set`);
        continue;
      }
      if (m.sender.userId !== state.turnUserId) {
        logger.warn(`[MATCHLOOP] Wrong player. Sender: ${m.sender.userId}, Expected: ${state.turnUserId}`);
        continue;
      }

      let payload: any;
      try {
        payload = JSON.parse(nk.binaryToString(m.data));
      } catch (e) {
        logger.warn(`[MATCHLOOP] Failed to parse payload: ${e}`);
        continue;
      }

      const index = Number(payload?.index);
      logger.info(`[MATCHLOOP] Move index: ${index}`);

      if (!Number.isInteger(index) || index < 0 || index > 8) {
        logger.warn(`[MATCHLOOP] Invalid index: ${index}`);
        continue;
      }
      if (state.board[index] !== "") {
        logger.warn(`[MATCHLOOP] Cell ${index} already occupied: ${state.board[index]}`);
        continue;
      }

      const mark = state.marksByUserId[m.sender.userId];
      logger.info(`[MATCHLOOP] Player mark: ${mark}`);

      if (!mark) {
        logger.warn(`[MATCHLOOP] No mark assigned for player ${m.sender.userId}`);
        logger.info(`[MATCHLOOP] Available marks: ${JSON.stringify(state.marksByUserId)}`);
        continue;
      }

      logger.info(`[MATCHLOOP] ✅ MOVE ACCEPTED! Placing ${mark} at index ${index}`);
      state.board[index] = mark;
      state.moveCount += 1;
      state.lastMoveAtMs = nowMs();

      const winner = computeWinner(state.board);
      if (winner) {
        state.status = "finished";
        state.winnerUserId =
          Object.keys(state.marksByUserId).find((uid) => state.marksByUserId[uid] === winner.mark) ?? null;
        state.winningLine = winner.line;
        state.turnUserId = null;
        state.turnDeadlineMs = null;
        state.label.open = false;
      } else if (isBoardFull(state.board)) {
        state.status = "finished";
        state.winnerUserId = null;
        state.winningLine = null;
        state.turnUserId = null;
        state.turnDeadlineMs = null;
        state.label.open = false;
      } else {
        setNextTurn(state);
      }

      broadcastState(dispatcher, state);
    }

    return { state };
  };

let matchTerminate: nkruntime.MatchTerminateFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  graceSeconds: number
) {
    return { state };
  };

let matchSignal: nkruntime.MatchSignalFunction = function (
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  dispatcher: nkruntime.MatchDispatcher,
  tick: number,
  state: MatchState,
  data: string
) {
    // Not used in this implementation, but required by some Nakama versions to avoid crashes
    // during match registration/introspection.
    return { state, data: "" };
  };

const RPC_CREATE_MATCH = "create-match";

type CreateMatchPayload = {
  mode?: Mode;
  turnTimeSec?: number;
};

function parseJson<T>(s: string | undefined): T | null {
  if (!s) return null;
  try {
    return JSON.parse(s) as T;
  } catch {
    return null;
  }
}

function CreateMatchRpc(ctx: nkruntime.Context, logger: nkruntime.Logger, nk: nkruntime.Nakama, payload: string) {
  const req = parseJson<CreateMatchPayload>(payload) ?? {};
  const mode: Mode = req.mode === "timed" ? "timed" : "classic";
  const turnTimeSec = typeof req.turnTimeSec === "number" ? req.turnTimeSec : undefined;
  const matchId = nk.matchCreate("tictactoe", { mode, turnTimeSec });
  return JSON.stringify({ matchId });
}

function OnMatchmakerMatched(ctx: nkruntime.Context, logger: nkruntime.Logger, nk: nkruntime.Nakama) {
  const matchId = nk.matchCreate("tictactoe", { mode: "classic" });
  return matchId;
}

function beforeMatchmakerAdd(
  ctx: nkruntime.Context,
  logger: nkruntime.Logger,
  nk: nkruntime.Nakama,
  envelope: nkruntime.Envelope
) {
  if (envelope.matchmakerAdd) {
    envelope.matchmakerAdd.minCount = 2;
    envelope.matchmakerAdd.maxCount = 2;
    const mode = envelope.matchmakerAdd.stringProperties?.["mode"];
    if (mode !== "timed" && mode !== "classic") {
      if (!envelope.matchmakerAdd.stringProperties) envelope.matchmakerAdd.stringProperties = {};
      envelope.matchmakerAdd.stringProperties["mode"] = "classic";
    }
  }
  return envelope;
}

function InitModule(ctx: nkruntime.Context, logger: nkruntime.Logger, nk: nkruntime.Nakama, initializer: nkruntime.Initializer) {
  initializer.registerMatch("tictactoe", {
    matchInit,
    matchJoinAttempt,
    matchJoin,
    matchLeave,
    matchLoop,
    matchSignal,
    matchTerminate,
  });
  initializer.registerRpc(RPC_CREATE_MATCH, CreateMatchRpc);
  initializer.registerMatchmakerMatched(OnMatchmakerMatched);
  initializer.registerRtBefore("MatchmakerAdd", beforeMatchmakerAdd);
  logger.info("Lila TicTacToe module loaded.");
}

// Reference InitModule so build tools don't remove it
!InitModule && InitModule.bind(null);
